+  --glass-highlight: rgba(255, 255, 255, 0.18);
+
+  --metal-light: #f5f5f6;
+  --metal-mid: #d5d7db;
+  --metal-dark: #9ea2a8;
+
+  --shadow-ambient: 0 28px 70px rgba(0, 0, 0, 0.45);
+  --shadow-contact: 0 6px 18px rgba(0, 0, 0, 0.25);
+
+  --radius-panel: 48px;
+  --radius-card: 20px;
