+    radial-gradient(circle at 0% 0%, rgba(58, 60, 68, 0.8) 0%, transparent 52%),
+    radial-gradient(circle at 100% 100%, rgba(58, 60, 68, 0.55) 0%, transparent 52%),
+    linear-gradient(135deg, #141518 0%, #070708 100%);
+  color: var(--text-primary);
+}
+
+.nav {
+  position: fixed;
+  top: 22px;
+  left: 50%;
+  transform: translateX(-50%);
+
+  display: flex;
+  align-items: center;
+  gap: 32px;
+  padding: 12px 24px;
+
+  background: rgba(255, 255, 255, 0.03);
+  backdrop-filter: blur(28px) saturate(135%);
+  -webkit-backdrop-filter: blur(28px) saturate(135%);
+
+  border: 1px solid rgba(255, 255, 255, 0.1);
+  border-top: 1px solid rgba(255, 255, 255, 0.18);
+  border-radius: var(--radius-pill);
+  z-index: 100;
+  box-shadow: 0 10px 42px rgba(0, 0, 0, 0.35);
+}
+
+.logo {
+  font-weight: 650;
+  font-size: 13px;
+  letter-spacing: -0.02em;
+  display: flex;
+  align-items: center;
+  gap: 10px;
+}
+
+.logo::before {
+  content: '';
+  display: block;
+  width: 12px;
+  height: 12px;
+  border-radius: 50%;
+  background: linear-gradient(135deg, var(--metal-light), var(--metal-dark));
+  box-shadow: inset 0 1px 1px rgba(255, 255, 255, 0.9), 0 1px 3px rgba(0, 0, 0, 0.7);
+}
+
+.navLinks {
+  display: flex;
+  gap: 24px;
+}
+
+.navLinks a {
+  color: rgba(246, 247, 248, 0.58);
+  text-decoration: none;
+  font-size: 13px;
+  font-weight: 430;
+  transition: color 0.2s ease;
+}
+
+.navLinks a:hover {
+  color: rgba(246, 247, 248, 0.92);
+}
+
+.main {
+  flex: 1;
+  display: grid;
+  grid-template-columns: 1fr 1.2fr;
+  max-width: 1600px;
+  margin: 0 auto;
+  width: 100%;
+  padding: 120px 80px 40px;
+  gap: 80px;
+}
+
+.textSection {
+  display: flex;
+  flex-direction: column;
+  justify-content: center;
+  position: relative;
+  z-index: 10;
+}
+
+.badge {
+  display: inline-flex;
+  align-items: center;
+  padding: 6px 12px;
+  background: rgba(255, 255, 255, 0.02);
+  border: 1px solid rgba(255, 255, 255, 0.08);
+  border-radius: var(--radius-pill);
+  font-size: 11px;
+  color: rgba(246, 247, 248, 0.62);
+  margin-bottom: 24px;
+  width: fit-content;
+  letter-spacing: 0.12em;
+  text-transform: uppercase;
+}
+
+.h1 {
+  font-size: 72px;
+  line-height: 1.05;
+  font-weight: 320;
+  letter-spacing: -0.05em;
+  margin-bottom: 22px;
+  color: var(--text-primary);
+  background: linear-gradient(180deg, rgba(255, 255, 255, 1) 0%, rgba(255, 255, 255, 0.44) 100%);
+  -webkit-background-clip: text;
+  -webkit-text-fill-color: transparent;
+  text-shadow: 0 0 28px rgba(255, 255, 255, 0.06);
+}
+
+.subhead {
+  font-size: 20px;
+  line-height: 1.5;
+  color: rgba(246, 247, 248, 0.64);
+  font-weight: 320;
+  max-width: 520px;
+  margin-bottom: 48px;
+  letter-spacing: -0.015em;
+}
+
+.ctaGroup {
+  display: flex;
+  align-items: center;
+  gap: 18px;
+}
+
+.btnPrimary {
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  width: 64px;
+  height: 64px;
+  border-radius: 50%;
+
+  background: radial-gradient(circle at 30% 30%, var(--metal-light) 0%, var(--metal-mid) 52%, var(--metal-dark) 100%);
+  border: 1px solid rgba(0, 0, 0, 0.25);
+  cursor: pointer;
+  position: relative;
+
+  box-shadow:
+    -4px -4px 12px rgba(255, 255, 255, 0.04),
+    10px 10px 28px rgba(0, 0, 0, 0.55),
+    inset -2px -2px 6px rgba(0, 0, 0, 0.22),
+    inset 2px 2px 6px rgba(255,  255, 255, 0.88);
+
+  transition: transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1), box-shadow 0.2s ease, filter 0.2s ease;
+}
+
+.btnPrimary::after {
+  content: '';
+  position: absolute;
+  inset: -9px;
+  border-radius: 50%;
+  background: radial-gradient(circle, rgba(255, 255, 255, 0.06) 0%, transparent 70%);
+  z-index: -1;
+  pointer-events: none;
+}
+
+.btnPrimary svg {
+  width: 24px;
+  height: 24px;
+  stroke: #0b0b0c;
+  stroke-width: 2;
+  stroke-linecap: round;
+  stroke-linejoin: round;
+  fill: none;
+  filter: drop-shadow(0px 1px 0px rgba(255, 255, 255, 0.45));
+}
+
+.btnPrimary:hover {
+  transform: scale(1.06);
+  filter: brightness(1.02);
+}
+
+.btnPrimary:active {
+  transform: scale(0.95);
+}
+
+.ctaText {
+  font-size: 14px;
+  font-weight: 560;
+  color: rgba(246, 247, 248, 0.92);
+  letter-spacing: -0.01em;
+}
+
+.canvasSection {
+  position: relative;
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  perspective: 1200px;
+}
+
+.spatialBackdrop {
+  position: absolute;
+  inset: 40px -40px -40px 40px;
+  background: linear-gradient(135deg, rgba(255, 255, 255, 0.028) 0%, rgba(0, 0, 0, 0.35) 100%);
+  border-radius: var(--radius-panel);
+  border-top: 1px solid rgba(255, 255, 255, 0.07);
+  border-left: 1px solid rgba(255, 255, 255, 0.07);
+  backdrop-filter: blur(44px);
+  -webkit-backdrop-filter: blur(44px);
+  box-shadow: -20px -20px 60px rgba(255, 255, 255, 0.02), 44px 44px 100px rgba(0, 0, 0, 0.6);
+  transform: rotateY(-15deg) rotateX(5deg) translateZ(-100px);
+  transform-style: preserve-3d;
+  pointer-events: none;
+}
+
+.spatialScene {
+  position: relative;
+  width: 100%;
+  height: 100%;
+  transform-style: preserve-3d;
+  transform: rotateY(-15deg) rotateX(5deg);
+}
+
+.splines {
+  position: absolute;
+  inset: 0;
+  width: 100%;
+  height: 100%;
+  z-index: 1;
+  transform: translateZ(0);
+}
+
+.splinePath {
+  fill: none;
+  stroke: rgba(255, 255, 255, 0.16);
+  stroke-width: 1.5;
+  stroke-dasharray: 6 6;
+  animation: flow 20s linear infinite;
+}
+
+.splineGlow {
+  fill: none;
+  stroke: rgba(255, 255, 255, 0.06);
+  stroke-width: 9;
+  filter: blur(5px);
+}
+
+@keyframes flow {
+  to {
+    stroke-dashoffset: -100;
+  }
+}
+
+.node {
+  position: absolute;
+  background: rgba(255, 255, 255, 0.028);
+  backdrop-filter: blur(18px) saturate(160%);
+  -webkit-backdrop-filter: blur(18px) saturate(160%);
+  border: 1px solid rgba(255, 255, 255, 0.1);
+  border-top: 1px solid rgba(255, 255, 255, 0.18);
+  border-radius: var(--radius-card);
+  box-shadow: var(--shadow-ambient), inset 0 1px 0 rgba(255, 255, 255, 0.12);
+  display: flex;
+  flex-direction: column;
+  z-index: 2;
+  transition: transform 0.4s cubic-bezier(0.2, 0.8, 0.2, 1), border-color 0.2s ease;
+}
+
+.node:hover {
+  transform: translateY(-8px) translateZ(40px);
+  border-color: rgba(255, 255, 255, 0.22);
+}
+
+.cardVideo {
+  width: 200px;
+  height: 120px;
+  padding: 12px;
+  display: flex;
+  flex-direction: column;
+  justify-content: space-between;
+}
+
+.cardVideoHeader {
+  display: flex;
+  align-items: center;
+  gap: 8px;
+}
+
+.avatar {
+  width: 20px;
+  height: 20px;
+  border-radius: 50%;
+  background: rgba(255, 255, 255, 0.1);
+}
+
+.cardTitle {
+  height: 4px;
+  width: 60%;
+  background: rgba(255, 255, 255, 0.22);
+  border-radius: 2px;
+}
+
+.cardMeta {
+  height: 4px;
+  width: 40%;
+  background: rgba(255, 255, 255, 0.12);
+  border-radius: 2px;
+  margin-top: 6px;
+}
+
+.playIndicator {
+  align-self: flex-end;
+  width: 24px;
+  height: 24px;
+  border-radius: 50%;
+  background: rgba(255, 255, 255, 0.1);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  backdrop-filter: blur(4px);
+}
+
+.playIndicator::after {
+  content: '';
+  width: 0;
+  height: 0;
+  border-style: solid;
+  border-width: 4px 0 4px 6px;
+  border-color: transparent transparent transparent rgba(255, 255, 255, 0.9);
+  margin-left: 2px;
+}
+
+.node1 {
+  top: 10%;
+  left: 10%;
+  transform: translateZ(20px);
+  animation: float 6s ease-in-out infinite;
+}
+
+.node2 {
+  top: 60%;
+  left: 5%;
+  transform: translateZ(40px);
+  animation: float 8s ease-in-out infinite 1s;
+}
+
+.node3 {
+  top: 15%;
+  right: 15%;
+  transform: translateZ(30px);
+  animation: float 7s ease-in-out infinite 2s;
+}
+
+.node4 {
+  top: 70%;
+  right: 10%;
+  transform: translateZ(10px);
+  animation: float 9s ease-in-out infinite 0.5s;
+}
+
+@keyframes float {
+  0%,
+  100% {
+    transform: translateY(0) translateZ(var(--tz, 20px));
+  }
+  50% {
+    transform: translateY(-12px) translateZ(var(--tz, 20px));
+  }
+}
+
+.nodeInsight {
+  top: 50%;
+  left: 50%;
+  transform: translate(-50%, -50%) translateZ(80px);
+  width: 140px;
+  height: 140px;
+  border-radius: 50%;
+  background: rgba(255, 255, 255, 0.028);
+  border: 1px solid rgba(255, 255, 255, 0.12);
+  box-shadow: 0 34px 88px rgba(0, 0, 0, 0.6), inset 0 2px 4px rgba(255, 255, 255, 0.12);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  z-index: 10;
+  position: absolute;
+}
+
+.insightCore {
+  width: 80px;
+  height: 80px;
+  border-radius: 50%;
+  background: radial-gradient(circle at 30% 30%, var(--metal-light) 0%, var(--metal-mid) 60%, var(--metal-dark) 100%);
+  box-shadow:
+    -4px -4px 12px rgba(255, 255, 255, 0.04),
+    10px 10px 28px rgba(0, 0, 0, 0.45),
+    inset -2px -2px 6px rgba(0, 0, 0, 0.25),
+    inset 2px 2px 6px rgba(255, 255, 255, 0.88);
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  position: relative;
+}
+
+.insightCore::before {
+  content: '';
+  position: absolute;
+  inset: -12px;
+  border-radius: 50%;
+  border: 1px solid rgba(255, 255, 255, 0.12);
+  animation: pulse 4s cubic-bezier(0.4, 0, 0.6, 1) infinite;
+}
+
+@keyframes pulse {
+  0% {
+    transform: scale(1);
+    opacity: 1;
+  }
+  100% {
+    transform: scale(1.5);
+    opacity: 0;
+  }
+}
+
+.insightCore svg {
+  width: 32px;
+  height: 32px;
+  stroke: #0b0b0c;
+  stroke-width: 1.5;
+  fill: none;
+  filter: drop-shadow(0px 1px 0px rgba(255, 255, 255, 0.55));
+}
+
+.metaLabel {
+  position: absolute;
+  font-size: 10px;
+  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace;
+  color: rgba(255, 255, 255, 0.45);
+  letter-spacing: 0.12em;
+  pointer-events: none;
+}
+
+.lbl1 {
+  bottom: -24px;
+  left: 50%;
+  transform: translateX(-50%);
+}
+
+.lbl2 {
+  top: -24px;
+  right: -20px;
+}
+
+@media (max-width: 1024px) {
+  .main {
+    grid-template-columns: 1fr;
+    padding: 100px 40px;
+    gap: 60px;
+  }
+
+  .canvasSection {
+    height: 500px;
+  }
+
+  .spatialScene {
+    transform: none;
+  }
+
+  .spatialBackdrop {
+    transform: none;
+  }
+}

