+
+.lbl2 {
+  top: -24px;
+  right: -20px;
+}
+
+@media (max-width: 1024px) {
+  .main {
+    grid-template-columns: 1fr;
+    padding: 100px 40px;
+    gap: 60px;
+  }
+
+  .canvasSection {
+    height: 500px;
+  }
+
+  .spatialScene {
+    transform: none;
+  }
+
+  .spatialBackdrop {
+    transform: none;
+  }
+}
