    transform: none;
  }

  .servicesSection {
    padding: 24px 40px 56px;
  }

  .servicesInner {
    justify-content: center;
  }

  .servicePanel {
    max-width: 100%;
  }

  .serviceHighlights {
    grid-template-columns: 1fr;
  }
}

