  display: grid;
  grid-template-columns: 1fr 1.2fr;
  max-width: 1600px;
  margin: 0 auto;
  width: 100%;
  padding: 120px 80px 32px;
  gap: 80px;
  overflow: visible;
}

.textSection {
  display: flex;
  flex-direction: column;
