  background: linear-gradient(135deg, rgba(255, 255, 255, 0.018) 0%, rgba(0, 0, 0, 0.55) 100%);
  border-radius: var(--radius-panel);
  border-top: 1px solid rgba(255, 255, 255, 0.07);
